const _pid = $('FA Webhook').first().json.body.property_id;
let cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();

try { const _p1 = JSON.parse(cleaned); return [{ json: { session_id: _sid, property_id: _pid, ..._p1, cascade_needed: !!_p1.cascade_needed } }]; } catch(_) {}

const start = cleaned.indexOf('{');
const lastEnd = cleaned.lastIndexOf('}');
if (start !== -1 && lastEnd > start) {
  try {
    const p = JSON.parse(cleaned.slice(start, lastEnd + 1));
    return [{ json: { session_id: _sid, property_id: _pid, ...p, cascade_needed: !!p.cascade_needed } }];
  } catch(_) {}
}

return [{ json: { session_id: _sid, property_id: _pid, cascade_needed: false, _parse_error: raw.substring(0, 300) } }];

parameters.jsonBody:
={{ (function() {
  const ip = $input.first().json;
  const INVALID = ['HEIRS OF','HEIR OF','ESTATE OF','UNKNOWN','CHILDREN OF','DESCENDANTS OF'];
  function isValidName(name) {
    if (!name || name.length < 3) return false;
    const u = name.toUpperCase();
    if (INVALID.some(p => u.startsWith(p))) return false;
    if (name.split(' ').filter(Boolean).length < 2) return false;
    return true;
  }
  return {
    session_id: ip.session_id,
    property_id: ip.property_id,
    persons: (ip.cascade_persons || [])
      .map(p => ({
        name: (p.name || '').replace(/\s*\(.*?\)/g, '').trim(),
        relationship_hint: (p.reason || 'cascade_heir').substring(0, 120)
      }))
      .filter(p => isValidName(p.name))
  };
})() }}

